// // This module converts an 8-bit binary input to a 3-bit output representing the analog voltage level as a fraction of the maximum 8-bit value (255). The output is calculated as (input * 7) / 255.
module dac_8bit (
    input [7:0] din,
    output reg [2:0] dout
);
    always @(*) begin
        dout = (din * 7 + 127) / 255; // Rounding to the nearest integer
    end
endmodule
